# prompt_filter.py -- Keyword and pattern-based prompt filter (Layer 1)
import re
from dataclasses import dataclass
from enum import Enum
from typing import Optional

class FilterVerdict(Enum):
    ALLOW = "allow"
    BLOCK = "block"
    FLAG  = "flag"   # allow but mark for downstream ML review

@dataclass
class FilterResult:
    verdict: FilterVerdict
    reason: Optional[str] = None
    matched_rule: Optional[str] = None

INJECTION_PATTERNS: list[tuple[str, str]] = [
    ("direct_override", r"ignore\s+(all\s+)?(previous|prior|above|your)\s+instructions"),
    ("role_swap",       r"you\s+are\s+now\s+(?:a|an|the)\s+\w+"),
    ("persona_swap",    r"(act|pretend|behave)\s+as\s+(?:if\s+)?(?:you\s+are\s+)?(?:a|an|the)"),
    ("system_fake",     r"<\|(?:im_start|system|user|assistant)\|>"),
    ("disregard_all",   r"disregard\s+(everything|all|any|the)"),
    ("new_directive",   r"your\s+new\s+(task|instructions?|directive)\s+is"),
    ("jailbreak_dan",   r"do\s+anything\s+now|DAN\s+mode"),
]
_COMPILED = [(name, re.compile(pat, re.IGNORECASE | re.DOTALL)) for name, pat in INJECTION_PATTERNS]

HARMFUL_COMBOS = [
    ("list all users",        ["database", "record", "dump"]),
    ("reveal your",           ["system prompt", "instructions", "config"]),
    ("step-by-step guide to", ["malware", "exploit", "hack", "explosive"]),
]

def filter_prompt_layer1(text: str) -> FilterResult:
    """Layer 1: <1ms keyword/pattern gate. Catches known-bad signatures."""
    if not text or not text.strip():
        return FilterResult(FilterVerdict.BLOCK, reason="empty_input")
    if len(text) > 32_000:
        return FilterResult(FilterVerdict.BLOCK, reason="exceeds_max_length")

    for name, pattern in _COMPILED:
        if pattern.search(text):
            return FilterResult(FilterVerdict.BLOCK, reason="injection_pattern", matched_rule=name)

    lower = text.lower()
    for trigger, domains in HARMFUL_COMBOS:
        if trigger in lower and any(d in lower for d in domains):
            return FilterResult(FilterVerdict.BLOCK, reason=f"harmful_combo:{trigger}")

    borderline = ["ignore", "override", "forget", "pretend", "roleplay"]
    if any(kw in lower for kw in borderline):
        return FilterResult(FilterVerdict.FLAG, reason="borderline_keyword")

    return FilterResult(FilterVerdict.ALLOW)

# ml_filter.py -- ML classifier (Layer 2) and topic boundary (Layer 3)
from __future__ import annotations
import hashlib, functools
from dataclasses import dataclass
from typing import Optional


class PromptClassifier:
    """
    Thin wrapper around an ML text classifier.
    In production, back this with a fine-tuned DistilBERT or an API
    such as Lakera Guard, LLM Guard, or a self-hosted HuggingFace pipeline.
    """
    INJECTION_THRESHOLD = 0.75
    TOXICITY_THRESHOLD  = 0.80

    def __init__(self):
        self._injection_kw = [
            "ignore", "override", "disregard", "pretend", "jailbreak",
            "system prompt", "new instructions", "forget everything",
        ]
        self._toxic_kw = ["hate", "kill", "attack", "harm", "illegal"]

    def _scores(self, text: str) -> tuple[float, float]:
        """Mocked scoring -- replace with real model.predict(text)."""
        lower = text.lower()
        inj = min(sum(1 for k in self._injection_kw if k in lower) * 0.25, 1.0)
        tox = min(sum(1 for k in self._toxic_kw if k in lower) * 0.30, 1.0)
        return inj, tox

    def is_safe(self, text: str) -> tuple[bool, Optional[str]]:
        inj, tox = self._scores(text)
        if inj >= self.INJECTION_THRESHOLD:
            return False, f"injection_score={inj:.2f}"
        if tox >= self.TOXICITY_THRESHOLD:
            return False, f"toxicity_score={tox:.2f}"
        return True, None


_classifier = PromptClassifier()

@functools.lru_cache(maxsize=8_192)
def _classify_cached(key: str, text: str) -> tuple[bool, Optional[str]]:
    return _classifier.is_safe(text)

def filter_prompt_layer2(text: str) -> tuple[bool, Optional[str]]:
    """Layer 2: ML semantic classifier with content-addressed result cache."""
    norm = " ".join(text.lower().split())
    key  = hashlib.sha256(norm.encode()).hexdigest()[:24]
    return _classify_cached(key, norm)


# --- Layer 3: Topic boundary enforcement ---

DOMAIN_KEYWORDS: dict[str, list[str]] = {
    "customer_support": [
        "order", "refund", "shipping", "product", "account",
        "billing", "delivery", "return", "invoice", "receipt",
    ],
    "medical_qa": [
        "symptom", "diagnosis", "medication", "dosage", "treatment",
        "doctor", "hospital", "prescription", "condition", "health",
    ],
}

def filter_prompt_layer3(text: str, domain: str = "customer_support") -> tuple[bool, str]:
    """Layer 3: Rejects prompts with no keywords matching the configured domain."""
    kw = DOMAIN_KEYWORDS.get(domain, [])
    if not kw:
        return True, "no_topic_constraints"
    lower = text.lower()
    if len(text.split()) < 30 and not any(k in lower for k in kw):
        return False, f"off_topic:{domain}"
    return True, "on_topic"
